var translation = {};

(async () => {
  try {
    const lang = localStorage.getItem("lang");
    
    if (!lang) {
      window.location.href = "lang.html";
      return;
    }

    // Wait for DOM to be ready
    if (document.readyState === 'loading') {
      await new Promise(resolve => {
        document.addEventListener('DOMContentLoaded', resolve);
      });
    }

    if (lang !== "en_us") {
      const cache = await caches.open("translation_cache");
      const cacheKey = `./lang/${lang}.json`;
      
      let cachedResponse = await cache.match(cacheKey);
      
      if (cachedResponse) {
        translation = await cachedResponse.json();
      } else {
        const fetchResponse = await fetch(cacheKey);
        translation = await fetchResponse.json();
        await cache.put(cacheKey, new Response(JSON.stringify(translation)));
      }
    }

    applyTranslations();
    Observer();

  } catch (error) {
    console.error("Translation failed:", error);
  }
})();

function applyTranslations() {
  const elements = document.querySelectorAll("h1, h2, h3, h4, h5, h6, p, span, a, button, option, label, li, td, th");
  let translationTemplate = {};
  
  if (localStorage.getItem("dev") === "true") {
    try {
      translationTemplate = JSON.parse(localStorage.getItem("translation") || "{}");
    } catch (e) {
      console.error("Failed to parse translation template:", e);
      translationTemplate = {};
    }
  }
  
  let hasChanges = false;
  
  elements.forEach(el => {
    
    if (el.getAttribute('data-translated') === 'true') return;
    
    const original = el.innerText.trim();
    if (!original) return;
    
    // Track all unique text in dev mode
    if (localStorage.getItem("dev") === "true") {
      if (!translationTemplate.hasOwnProperty(original)) {
        translationTemplate[original] = translation[original] || "";
        hasChanges = true;
      }
    }
    
    if (translation[original]) {
      console.info("Translating:", original, "->", translation[original]);
      el.innerText = translation[original];
      el.setAttribute('data-translated', 'true');
      el.setAttribute('data-original', original);
    } else if (original !== "") {
      console.warn("No translation found for:", original);
    }
  });
  
  if (localStorage.getItem("dev") === "true" && hasChanges) {
    localStorage.setItem("translation", JSON.stringify(translationTemplate, null, 2));
    console.log("Translation template updated in localStorage");
  }
}

function Observer() {
  // Check if document.body exists
  if (!document.body) {
    console.warn("Document body not ready, retrying observer in 100ms");
    setTimeout(Observer, 100);
    return;
  }
  
  // Use MutationObserver for better performance instead of setInterval
  const observer = new MutationObserver((mutations) => {
    let shouldUpdate = false;
    
    for (const mutation of mutations) {
      // Check if new nodes were added
      if (mutation.type === 'childList' && mutation.addedNodes.length > 0) {
        shouldUpdate = true;
        break;
      }
      // Check if text content changed
      if (mutation.type === 'characterData') {
        shouldUpdate = true;
        break;
      }
      // Check if attributes that might affect text changed
      if (mutation.type === 'attributes' && 
          (mutation.attributeName === 'textContent' || 
           mutation.attributeName === 'innerText' ||
           mutation.attributeName === 'data-original')) {
        shouldUpdate = true;
        break;
      }
    }
    
    if (shouldUpdate) {
      // Small delay to allow DOM to settle
      setTimeout(() => applyTranslations(), 50);
    }
  });
  
  // Start observing
  observer.observe(document.body, {
    childList: true,
    subtree: true,
    characterData: true,
    attributes: true,
    attributeFilter: ['textContent', 'innerText', 'data-original']
  });
  
  // Also run periodically as a fallback (but less frequently)
  setInterval(() => {
    applyTranslations();
  }, 2000);
}

// Optional: Export translation template as JSON file (for dev mode)
function exportTranslationTemplate() {
  if (localStorage.getItem("dev") !== "true") {
    console.warn("Developer mode is not enabled");
    return;
  }
  
  const template = localStorage.getItem("translation");
  if (!template) {
    console.warn("No translation template found");
    return;
  }
  
  const blob = new Blob([template], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `translation_template_${new Date().toISOString().slice(0,19)}.json`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  
  console.log("Translation template exported");
}

// Optional: Clear translation cache
async function clearTranslationCache() {
  try {
    const cache = await caches.open("translation_cache");
    const keys = await cache.keys();
    for (const key of keys) {
      if (key.url.includes("/lang/")) {
        await cache.delete(key);
      }
    }
    console.log("Translation cache cleared");
  } catch (error) {
    console.error("Failed to clear cache:", error);
  }
}

// Make helper functions available in console for dev mode
if (typeof window !== 'undefined') {
  window.exportTranslationTemplate = exportTranslationTemplate;
  window.clearTranslationCache = clearTranslationCache;
}